import React, { useState, useEffect } from 'react';
import { KANA_DATA } from '../constants';

interface KanaGameProps {
  onComplete: (score: number) => void;
  onBack: () => void;
}

const KanaGame: React.FC<KanaGameProps> = ({ onComplete, onBack }) => {
  const [currentIdx, setCurrentIdx] = useState(0);
  const [options, setOptions] = useState<string[]>([]);
  const [message, setMessage] = useState<{ text: string, type: 'success' | 'error' } | null>(null);
  const [mistakes, setMistakes] = useState(0);

  const generateOptions = (correct: string) => {
    const others = KANA_DATA.filter(k => k.romaji !== correct)
      .map(k => k.romaji)
      .sort(() => Math.random() - 0.5)
      .slice(0, 3);
    return [...others, correct].sort(() => Math.random() - 0.5);
  };

  useEffect(() => {
    if (currentIdx < KANA_DATA.length) {
      setOptions(generateOptions(KANA_DATA[currentIdx].romaji));
    } else {
      onComplete(Math.max(0, 100 - mistakes * 10));
    }
  }, [currentIdx]);

  const handleSelect = (selected: string) => {
    if (selected === KANA_DATA[currentIdx].romaji) {
      setMessage({ text: 'Excellent! 正解です！', type: 'success' });
      setTimeout(() => {
        setMessage(null);
        setCurrentIdx(prev => prev + 1);
      }, 800);
    } else {
      setMistakes(prev => prev + 1);
      setMessage({ text: 'Try again! 違います', type: 'error' });
      setTimeout(() => setMessage(null), 800);
    }
  };

  if (currentIdx >= KANA_DATA.length) return null;

  return (
    <div className="flex flex-col items-center justify-center py-10 space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
      <button onClick={onBack} className="absolute top-4 left-4 text-gray-400 hover:text-gray-600">
        <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M10 19l-7-7m0 0l7-7m-7 7h18" /></svg>
      </button>

      <div className="w-full bg-gray-200 h-2 rounded-full mb-4">
        <div className="bg-blue-600 h-full rounded-full transition-all" style={{ width: `${(currentIdx / KANA_DATA.length) * 100}%` }} />
      </div>

      <div className="bg-white w-40 h-40 rounded-3xl shadow-xl border-4 border-blue-50 flex items-center justify-center relative">
        <span className="text-8xl font-bold text-gray-800">{KANA_DATA[currentIdx].char}</span>
        {message && (
          <div className={`absolute -top-4 px-4 py-1 rounded-full text-white text-sm font-bold shadow-lg animate-bounce ${message.type === 'success' ? 'bg-green-500' : 'bg-red-500'}`}>
            {message.text}
          </div>
        )}
      </div>

      <p className="text-gray-500 font-medium">Which romaji is this?</p>

      <div className="grid grid-cols-2 gap-4 w-full px-4">
        {options.map((opt, i) => (
          <button
            key={i}
            onClick={() => handleSelect(opt)}
            className="bg-white border-2 border-gray-100 py-6 rounded-2xl text-2xl font-bold text-gray-700 hover:border-blue-400 hover:bg-blue-50 active:scale-95 transition-all shadow-sm"
          >
            {opt}
          </button>
        ))}
      </div>
    </div>
  );
};

export default KanaGame;

import React, { useState } from 'react';
import { MOCK_CLASSES, MOCK_STUDENTS } from '../constants';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell } from 'recharts';

const TeacherDashboard: React.FC = () => {
  const [selectedClass, setSelectedClass] = useState<string | null>(null);

  const exportData = () => {
    const csvRows = [
      ['Student Name', 'Class', 'Login Count', 'Completion %', 'Points'],
      ...MOCK_STUDENTS.map(s => [s.name, s.className, s.loginCount.toString(), s.completionRate.toString(), s.totalPoints.toString()])
    ];

    const csvContent = "data:text/csv;charset=utf-8," + csvRows.map(e => e.join(",")).join("\n");
    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", "japanese_class_report.csv");
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const chartData = MOCK_CLASSES.map(c => ({
    name: c.name.split(' ').slice(-1)[0],
    completion: c.avgCompletion,
  }));

  return (
    <div className="space-y-6 pb-20">
      <header className="flex justify-between items-center">
        <h2 className="text-xl font-bold text-gray-800">Class Analytics</h2>
        <button 
          onClick={exportData}
          className="bg-blue-600 text-white text-xs px-3 py-2 rounded-lg font-bold hover:bg-blue-700 shadow-md flex items-center gap-2"
        >
          <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>
          Export CSV
        </button>
      </header>

      {/* Stats Summary */}
      <section className="bg-white p-4 rounded-xl border border-gray-100 shadow-sm h-64">
        <p className="text-gray-500 text-xs font-bold mb-4 uppercase">Avg. Completion Rate per Class</p>
        <ResponsiveContainer width="100%" height="80%">
          <BarChart data={chartData}>
            <CartesianGrid strokeDasharray="3 3" vertical={false} />
            <XAxis dataKey="name" fontSize={12} />
            <YAxis fontSize={12} />
            <Tooltip />
            <Bar dataKey="completion" radius={[4, 4, 0, 0]}>
              {chartData.map((entry, index) => (
                <Cell key={`cell-${index}`} fill={index % 2 === 0 ? '#3B82F6' : '#10B981'} />
              ))}
            </Bar>
          </BarChart>
        </ResponsiveContainer>
      </section>

      {/* Class Selector */}
      <section className="space-y-3">
        <h3 className="font-bold text-gray-700">Manage Classes</h3>
        <div className="grid grid-cols-1 gap-3">
          {MOCK_CLASSES.map(c => (
            <div 
              key={c.id} 
              className="bg-white p-4 rounded-xl border border-gray-100 shadow-sm flex justify-between items-center"
            >
              <div>
                <h4 className="font-bold text-gray-800 text-sm">{c.name}</h4>
                <p className="text-xs text-gray-500">{c.studentCount} Students</p>
              </div>
              <button 
                onClick={() => setSelectedClass(selectedClass === c.id ? null : c.id)}
                className="text-blue-600 text-xs font-bold"
              >
                {selectedClass === c.id ? 'Close' : 'View Students'}
              </button>
            </div>
          ))}
        </div>
      </section>

      {/* Student List (Conditional) */}
      {selectedClass && (
        <section className="space-y-3 animate-in slide-in-from-top-2 duration-300">
          <div className="flex justify-between items-center">
            <h3 className="font-bold text-gray-700">Student Progress</h3>
            <span className="text-[10px] text-gray-400 uppercase font-bold">Class ID: {selectedClass}</span>
          </div>
          <div className="bg-white rounded-xl border border-gray-100 overflow-hidden shadow-sm">
            <table className="w-full text-left text-xs">
              <thead className="bg-gray-50 border-b text-gray-500 uppercase tracking-tighter">
                <tr>
                  <th className="px-4 py-3 font-bold">Name</th>
                  <th className="px-4 py-3 font-bold text-center">Login</th>
                  <th className="px-4 py-3 font-bold text-center">Score</th>
                  <th className="px-4 py-3 font-bold text-right">Points</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-gray-50">
                {MOCK_STUDENTS.map(s => (
                  <tr key={s.id} className="hover:bg-blue-50/30 transition-colors">
                    <td className="px-4 py-3 font-medium text-gray-800">{s.name}</td>
                    <td className="px-4 py-3 text-center">{s.loginCount}</td>
                    <td className="px-4 py-3 text-center">
                      <span className={`px-2 py-1 rounded-full text-[10px] font-bold ${
                        s.completionRate > 80 ? 'bg-green-100 text-green-700' : 'bg-orange-100 text-orange-700'
                      }`}>
                        {s.completionRate}%
                      </span>
                    </td>
                    <td className="px-4 py-3 text-right font-bold text-blue-600">{s.totalPoints}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </section>
      )}
    </div>
  );
};

export default TeacherDashboard;

