import React, { useState, useEffect } from 'react';
import { KANA_DATA } from '../constants';

interface KanaGameProps {
  onComplete: (score: number) => void;
  onBack: () => void;
}

const KanaGame: React.FC<KanaGameProps> = ({ onComplete, onBack }) => {
  const [gamePool, setGamePool] = useState<{char: string, romaji: string}[]>([]);
  const [currentIdx, setCurrentIdx] = useState(0);
  const [options, setOptions] = useState<string[]>([]);
  const [message, setMessage] = useState<{ text: string, type: 'success' | 'error' } | null>(null);
  const [mistakes, setMistakes] = useState(0);

  useEffect(() => {
    // Shuffle all 46 and take a subset or all
    const shuffled = [...KANA_DATA].sort(() => Math.random() - 0.5);
    setGamePool(shuffled.slice(0, 10)); // Just 10 random ones per round to keep it snappy
  }, []);

  const generateOptions = (correct: string) => {
    const others = KANA_DATA.filter(k => k.romaji !== correct)
      .map(k => k.romaji)
      .sort(() => Math.random() - 0.5)
      .slice(0, 3);
    return [...others, correct].sort(() => Math.random() - 0.5);
  };

  useEffect(() => {
    if (gamePool.length > 0 && currentIdx < gamePool.length) {
      setOptions(generateOptions(gamePool[currentIdx].romaji));
    } else if (gamePool.length > 0) {
      onComplete(Math.max(0, 100 - mistakes * 5));
    }
  }, [currentIdx, gamePool]);

  const handleSelect = (selected: string) => {
    if (selected === gamePool[currentIdx].romaji) {
      setMessage({ text: '太棒了！正解', type: 'success' });
      setTimeout(() => {
        setMessage(null);
        setCurrentIdx(prev => prev + 1);
      }, 800);
    } else {
      setMistakes(prev => prev + 1);
      setMessage({ text: '再试试？违い', type: 'error' });
      setTimeout(() => setMessage(null), 800);
    }
  };

  if (gamePool.length === 0 || currentIdx >= gamePool.length) return (
    <div className="flex items-center justify-center h-full">
      <div className="animate-spin rounded-full h-12 w-12 border-t-4 border-[#FF6B6B]"></div>
    </div>
  );

  return (
    <div className="flex flex-col items-center justify-center py-6 space-y-8 animate-in fade-in zoom-in-95 duration-500 relative">
      <button onClick={onBack} className="absolute -top-1 -left-2 p-2 text-gray-400 hover:text-[#FF6B6B] transition-colors">
        <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M15 19l-7-7 7-7" /></svg>
      </button>

      <div className="w-full px-4">
        <div className="flex justify-between items-end mb-2">
          <span className="text-xs font-black text-[#FF6B6B] uppercase tracking-tighter">进度 {currentIdx + 1}/{gamePool.length}</span>
          <span className="text-xs font-black text-gray-300 uppercase tracking-tighter">失误: {mistakes}</span>
        </div>
        <div className="w-full bg-gray-100 h-4 rounded-full overflow-hidden shadow-inner p-1">
          <div className="bg-gradient-to-r from-[#FF6B6B] to-[#FFE66D] h-full rounded-full transition-all duration-500 shadow-sm" style={{ width: `${((currentIdx + 1) / gamePool.length) * 100}%` }} />
        </div>
      </div>

      <div className="bg-white w-52 h-52 rounded-[3rem] shadow-[0_20px_40px_rgba(255,107,107,0.2)] border-8 border-[#FFEDED] flex items-center justify-center relative transform -rotate-2">
        <span className="text-[100px] font-black text-gray-800 select-none">{gamePool[currentIdx].char}</span>
        {message && (
          <div className={`absolute -bottom-6 px-6 py-2 rounded-2xl text-white text-lg font-black shadow-xl animate-bounce z-10 ${message.type === 'success' ? 'bg-[#4ECDC4]' : 'bg-[#FF6B6B]'}`}>
            {message.text}
          </div>
        )}
      </div>

      <div className="text-center px-4">
        <h2 className="text-lg font-black text-gray-700">请选择正确的罗马音：</h2>
      </div>

      <div className="grid grid-cols-2 gap-4 w-full px-2">
        {options.map((opt, i) => (
          <button
            key={i}
            onClick={() => handleSelect(opt)}
            className="bg-white border-2 border-gray-100 py-6 rounded-[2rem] text-3xl font-black text-gray-700 hover:border-[#FF6B6B] hover:text-[#FF6B6B] hover:bg-[#FFEDED] active:scale-90 transition-all shadow-md group"
          >
            <span className="group-hover:scale-110 inline-block transition-transform">{opt}</span>
          </button>
        ))}
      </div>
    </div>
  );
};

export default KanaGame;

import React, { useState, useEffect, useRef } from 'react';
import { KANA_DATA } from '../constants';

interface PuzzleGameProps {
  onComplete: (score: number) => void;
  onBack: () => void;
}

const PuzzleGame: React.FC<PuzzleGameProps> = ({ onComplete, onBack }) => {
  const [timeLeft, setTimeLeft] = useState(30);
  const [targetKana, setTargetKana] = useState<typeof KANA_DATA[0] | null>(null);
  const [pieces, setPieces] = useState<{id: number, type: 'correct' | 'wrong', pos: number, char: string}[]>([]);
  const [selectedIds, setSelectedIds] = useState<number[]>([]);
  const [score, setScore] = useState(0);
  const timerRef = useRef<number | null>(null);

  const startNewRound = () => {
    const target = KANA_DATA[Math.floor(Math.random() * KANA_DATA.length)];
    const distractor = KANA_DATA[Math.floor(Math.random() * KANA_DATA.length)];
    setTargetKana(target);
    setSelectedIds([]);

    // Create 4 correct pieces (representing quadrants 0,1,2,3)
    const correctPieces = [0, 1, 2, 3].map(pos => ({
      id: Math.random(),
      type: 'correct' as const,
      pos,
      char: target.char
    }));

    // Add 1 wrong piece from a random quadrant of distractor
    const wrongPiece = {
      id: Math.random(),
      type: 'wrong' as const,
      pos: Math.floor(Math.random() * 4),
      char: distractor.id === target.id ? 'あ' : distractor.char // simple avoid match
    };

    const allPieces = [...correctPieces, wrongPiece].sort(() => Math.random() - 0.5);
    setPieces(allPieces);
  };

  useEffect(() => {
    startNewRound();
    timerRef.current = window.setInterval(() => {
      setTimeLeft(prev => {
        if (prev <= 1) {
          if (timerRef.current) clearInterval(timerRef.current);
          return 0;
        }
        return prev - 1;
      });
    }, 1000);
    return () => { if (timerRef.current) clearInterval(timerRef.current); };
  }, []);

  useEffect(() => {
    if (timeLeft === 0) {
      onComplete(score);
    }
  }, [timeLeft]);

  const togglePiece = (piece: typeof pieces[0]) => {
    if (selectedIds.includes(piece.id)) {
      setSelectedIds(prev => prev.filter(id => id !== piece.id));
    } else {
      if (selectedIds.length < 4) {
        const next = [...selectedIds, piece.id];
        setSelectedIds(next);

        // If 4 selected, check if all are correct
        if (next.length === 4) {
          const selectedPieces = pieces.filter(p => next.includes(p.id));
          const isAllCorrect = selectedPieces.every(p => p.type === 'correct');
          if (isAllCorrect) {
            setScore(prev => prev + 10);
            setTimeout(startNewRound, 500);
          } else {
            // Shake or penalty?
            setScore(prev => Math.max(0, prev - 5));
            setTimeout(() => setSelectedIds([]), 500);
          }
        }
      }
    }
  };

  // Fragment styling based on quadrant (pos)
  const getFragmentClip = (pos: number) => {
    switch(pos) {
      case 0: return 'clip-path: inset(0 50% 50% 0)'; // Top Left
      case 1: return 'clip-path: inset(0 0 50% 50%)'; // Top Right
      case 2: return 'clip-path: inset(50% 50% 0 0)'; // Bottom Left
      case 3: return 'clip-path: inset(50% 0 0 50%)'; // Bottom Right
      default: return '';
    }
  };

  return (
    <div className="flex flex-col items-center py-2 space-y-6">
      <button onClick={onBack} className="absolute -top-1 -left-2 p-2 text-gray-400 hover:text-[#FF6B6B]">
        <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M15 19l-7-7 7-7" /></svg>
      </button>

      <div className="w-full px-4 flex justify-between items-center bg-white p-4 rounded-3xl border-2 border-orange-100 shadow-sm">
        <div className="flex flex-col">
          <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest">倒计时</span>
          <span className={`text-2xl font-black ${timeLeft < 10 ? 'text-red-500 animate-pulse' : 'text-[#FF6B6B]'}`}>{timeLeft}s</span>
        </div>
        <div className="text-center">
          <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest">目标假名</span>
          <h2 className="text-3xl font-black text-blue-500">{targetKana?.char}</h2>
        </div>
        <div className="flex flex-col items-end">
          <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest">当前得分</span>
          <span className="text-2xl font-black text-green-500">{score}</span>
        </div>
      </div>

      <p className="text-gray-500 font-bold text-center text-sm px-6 leading-relaxed">
        找到属于 <span className="text-[#FF6B6B] font-black text-lg">{targetKana?.char}</span> 的 <span className="text-blue-500 font-black">4个</span> 正确拼图碎片！
      </p>

      {/* Grid of fragments */}
      <div className="grid grid-cols-2 gap-6 w-full px-4">
        {pieces.map((piece) => (
          <button
            key={piece.id}
            onClick={() => togglePiece(piece)}
            className={`aspect-square bg-white rounded-3xl border-4 transition-all overflow-hidden flex items-center justify-center relative shadow-lg ${
              selectedIds.includes(piece.id) ? 'border-[#4ECDC4] bg-[#EFFFFD] scale-95' : 'border-gray-100 hover:border-blue-200'
            }`}
          >
            <div 
              className="text-[120px] font-black text-gray-800 absolute opacity-80"
              style={{ clipPath: getFragmentClip(piece.pos).replace('clip-path: ', '') }}
            >
              {piece.char}
            </div>
            {selectedIds.includes(piece.id) && (
              <div className="absolute inset-0 bg-[#4ECDC4]/20 flex items-center justify-center">
                <svg className="w-12 h-12 text-[#4ECDC4]" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z" clipRule="evenodd" /></svg>
              </div>
            )}
          </button>
        ))}
      </div>

      <div className="text-[10px] text-gray-400 font-bold uppercase tracking-widest">
        已选择 {selectedIds.length}/4
      </div>
    </div>
  );
};

export default PuzzleGame;

