import React, { useState, useEffect, useRef } from 'react';
import { KANA_DATA } from '../constants';

interface PuzzleGameProps {
  onComplete: (score: number) => void;
  onBack: () => void;
}

const PuzzleGame: React.FC<PuzzleGameProps> = ({ onComplete, onBack }) => {
  const [timeLeft, setTimeLeft] = useState(30);
  const [targetKana, setTargetKana] = useState<typeof KANA_DATA[0] | null>(null);
  const [pieces, setPieces] = useState<{id: number, type: 'correct' | 'wrong', pos: number, char: string}[]>([]);
  const [selectedIds, setSelectedIds] = useState<number[]>([]);
  const [score, setScore] = useState(0);
  const timerRef = useRef<number | null>(null);

  const startNewRound = () => {
    const target = KANA_DATA[Math.floor(Math.random() * KANA_DATA.length)];
    const distractor = KANA_DATA[Math.floor(Math.random() * KANA_DATA.length)];
    setTargetKana(target);
    setSelectedIds([]);

    // Create 4 correct pieces (representing quadrants 0,1,2,3)
    const correctPieces = [0, 1, 2, 3].map(pos => ({
      id: Math.random(),
      type: 'correct' as const,
      pos,
      char: target.char
    }));

    // Add 1 wrong piece from a random quadrant of distractor
    // Fix: Use 'char' instead of 'id' for comparison as KANA_DATA objects don't have an 'id' property
    const wrongPiece = {
      id: Math.random(),
      type: 'wrong' as const,
      pos: Math.floor(Math.random() * 4),
      char: distractor.char === target.char ? 'あ' : distractor.char // simple avoid match
    };

    const allPieces = [...correctPieces, wrongPiece].sort(() => Math.random() - 0.5);
    setPieces(allPieces);
  };

  useEffect(() => {
    startNewRound();
    timerRef.current = window.setInterval(() => {
      setTimeLeft(prev => {
        if (prev <= 1) {
          if (timerRef.current) clearInterval(timerRef.current);
          return 0;
        }
        return prev - 1;
      });
    }, 1000);
    return () => { if (timerRef.current) clearInterval(timerRef.current); };
  }, []);

  useEffect(() => {
    if (timeLeft === 0) {
      onComplete(score);
    }
  }, [timeLeft]);

  const togglePiece = (piece: typeof pieces[0]) => {
    if (selectedIds.includes(piece.id)) {
      setSelectedIds(prev => prev.filter(id => id !== piece.id));
    } else {
      if (selectedIds.length < 4) {
        const next = [...selectedIds, piece.id];
        setSelectedIds(next);

        // If 4 selected, check if all are correct
        if (next.length === 4) {
          const selectedPieces = pieces.filter(p => next.includes(p.id));
          const isAllCorrect = selectedPieces.every(p => p.type === 'correct');
          if (isAllCorrect) {
            setScore(prev => prev + 10);
            setTimeout(startNewRound, 500);
          } else {
            // Shake or penalty?
            setScore(prev => Math.max(0, prev - 5));
            setTimeout(() => setSelectedIds([]), 500);
          }
        }
      }
    }
  };

  // Fragment styling based on quadrant (pos)
  const getFragmentClip = (pos: number) => {
    switch(pos) {
      case 0: return 'clip-path: inset(0 50% 50% 0)'; // Top Left
      case 1: return 'clip-path: inset(0 0 50% 50%)'; // Top Right
      case 2: return 'clip-path: inset(50% 50% 0 0)'; // Bottom Left
      case 3: return 'clip-path: inset(50% 0 0 50%)'; // Bottom Right
      default: return '';
    }
  };

  return (
    <div className="flex flex-col items-center py-2 space-y-6">
      <button onClick={onBack} className="absolute -top-1 -left-2 p-2 text-gray-400 hover:text-[#FF6B6B]">
        <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M15 19l-7-7 7-7" /></svg>
      </button>

      <div className="w-full px-4 flex justify-between items-center bg-white p-4 rounded-3xl border-2 border-orange-100 shadow-sm">
        <div className="flex flex-col">
          <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest">倒计时</span>
          <span className={`text-2xl font-black ${timeLeft < 10 ? 'text-red-500 animate-pulse' : 'text-[#FF6B6B]'}`}>{timeLeft}s</span>
        </div>
        <div className="text-center">
          <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest">目标假名</span>
          <h2 className="text-3xl font-black text-blue-500">{targetKana?.char}</h2>
        </div>
        <div className="flex flex-col items-end">
          <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest">当前得分</span>
          <span className="text-2xl font-black text-green-500">{score}</span>
        </div>
      </div>

      <p className="text-gray-500 font-bold text-center text-sm px-6 leading-relaxed">
        找到属于 <span className="text-[#FF6B6B] font-black text-lg">{targetKana?.char}</span> 的 <span className="text-blue-500 font-black">4个</span> 正确拼图碎片！
      </p>

      {/* Grid of fragments */}
      <div className="grid grid-cols-2 gap-6 w-full px-4">
        {pieces.map((piece) => (
          <button
            key={piece.id}
            onClick={() => togglePiece(piece)}
            className={`aspect-square bg-white rounded-3xl border-4 transition-all overflow-hidden flex items-center justify-center relative shadow-lg ${
              selectedIds.includes(piece.id) ? 'border-[#4ECDC4] bg-[#EFFFFD] scale-95' : 'border-gray-100 hover:border-blue-200'
            }`}
          >
            <div 
              className="text-[120px] font-black text-gray-800 absolute opacity-80"
              style={{ clipPath: getFragmentClip(piece.pos).replace('clip-path: ', '') }}
            >
              {piece.char}
            </div>
            {selectedIds.includes(piece.id) && (
              <div className="absolute inset-0 bg-[#4ECDC4]/20 flex items-center justify-center">
                <svg className="w-12 h-12 text-[#4ECDC4]" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z" clipRule="evenodd" /></svg>
              </div>
            )}
          </button>
        ))}
      </div>

      <div className="text-[10px] text-gray-400 font-bold uppercase tracking-widest">
        已选择 {selectedIds.length}/4
      </div>
    </div>
  );
};

