};

import React, { useState, useEffect } from 'react';
import { KANA_DATA } from '../constants';

interface KanaGameProps {
  onComplete: (score: number) => void;
  onBack: () => void;
}

const KanaGame: React.FC<KanaGameProps> = ({ onComplete, onBack }) => {
  const [gamePool, setGamePool] = useState<{char: string, romaji: string}[]>([]);
  const [currentIdx, setCurrentIdx] = useState(0);
  const [options, setOptions] = useState<string[]>([]);
  const [message, setMessage] = useState<{ text: string, type: 'success' | 'error' } | null>(null);
  const [mistakes, setMistakes] = useState(0);

  // 更加可靠的随机排序算法
  const shuffleArray = <T,>(array: T[]): T[] => {
    const newArr = [...array];
    for (let i = newArr.length - 1; i > 0; i--) {
      const j = Math.floor(Math.random() * (i + 1));
      [newArr[i], newArr[j]] = [newArr[j], newArr[i]];
    }
    return newArr;
  };

  useEffect(() => {
    const shuffled = shuffleArray([...KANA_DATA]);
    setGamePool(shuffled.slice(0, 10));
  }, []);

  const generateOptions = (correct: string) => {
    const others = KANA_DATA.filter(k => k.romaji !== correct)
      .map(k => k.romaji);
    const shuffledOthers = shuffleArray(others).slice(0, 3);
    return shuffleArray([...shuffledOthers, correct]);
  };

  useEffect(() => {
    if (gamePool.length > 0 && currentIdx < gamePool.length) {
      setOptions(generateOptions(gamePool[currentIdx].romaji));
    } else if (gamePool.length > 0) {
      onComplete(Math.max(0, 100 - mistakes * 5));
    }
  }, [currentIdx, gamePool]);

  const handleSelect = (selected: string) => {
    if (selected === gamePool[currentIdx].romaji) {
      setMessage({ text: '太棒了！正解', type: 'success' });
      setTimeout(() => {
        setMessage(null);
        setCurrentIdx(prev => prev + 1);
      }, 800);
    } else {
      setMistakes(prev => prev + 1);
      setMessage({ text: '再试试？违い', type: 'error' });
      setTimeout(() => setMessage(null), 800);
    }
  };

  if (gamePool.length === 0 || currentIdx >= gamePool.length) return (
    <div className="flex items-center justify-center h-full">
      <div className="animate-spin rounded-full h-12 w-12 border-t-4 border-[#FF6B6B]"></div>
    </div>
  );

  return (
    <div className="flex flex-col items-center justify-center py-6 space-y-8 animate-in fade-in zoom-in-95 duration-500 relative">
      <button onClick={onBack} className="absolute -top-1 -left-2 p-2 text-gray-400 hover:text-[#FF6B6B] transition-colors">
        <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M15 19l-7-7 7-7" /></svg>
      </button>

      <div className="w-full px-4">
        <div className="flex justify-between items-end mb-2">
          <span className="text-xs font-black text-[#FF6B6B] uppercase tracking-tighter">进度 {currentIdx + 1}/{gamePool.length}</span>
          <span className="text-xs font-black text-gray-300 uppercase tracking-tighter">失误: {mistakes}</span>
        </div>
        <div className="w-full bg-gray-100 h-4 rounded-full overflow-hidden shadow-inner p-1">
          <div className="bg-gradient-to-r from-[#FF6B6B] to-[#FFE66D] h-full rounded-full transition-all duration-500 shadow-sm" style={{ width: `${((currentIdx + 1) / gamePool.length) * 100}%` }} />
        </div>
      </div>

      <div className="bg-white w-52 h-52 rounded-[3rem] shadow-[0_20px_40px_rgba(255,107,107,0.2)] border-8 border-[#FFEDED] flex items-center justify-center relative transform -rotate-2">
        <span className="text-[100px] font-black text-gray-800 select-none">{gamePool[currentIdx].char}</span>
        {message && (
          <div className={`absolute -bottom-6 px-6 py-2 rounded-2xl text-white text-lg font-black shadow-xl animate-bounce z-10 ${message.type === 'success' ? 'bg-[#4ECDC4]' : 'bg-[#FF6B6B]'}`}>
            {message.text}
          </div>
        )}
      </div>

      <div className="text-center px-4">
        <h2 className="text-lg font-black text-gray-700">请选择正确的罗马音：</h2>
      </div>

      <div className="grid grid-cols-2 gap-4 w-full px-2">
        {options.map((opt, i) => (
          <button
            key={`${currentIdx}-${i}`}
            onClick={() => handleSelect(opt)}
            className="bg-white border-2 border-gray-100 py-6 rounded-[2rem] text-3xl font-black text-gray-700 hover:border-[#FF6B6B] hover:text-[#FF6B6B] hover:bg-[#FFEDED] active:scale-90 transition-all shadow-md group"
          >
            <span className="group-hover:scale-110 inline-block transition-transform">{opt}</span>
          </button>
        ))}
      </div>
    </div>
  );
};

export default KanaGame;

import React, { useState, useEffect, useRef } from 'react';
import { KANA_DATA } from '../constants';

interface Piece {
  id: string;
  char: string;
  quadrant: number; // 0:TL, 1:TR, 2:BL, 3:BR
  isDistractor: boolean;
}

interface PuzzleGameProps {
  onComplete: (score: number) => void;
  onBack: () => void;
}

const PuzzleGame: React.FC<PuzzleGameProps> = ({ onComplete, onBack }) => {
  const [timeLeft, setTimeLeft] = useState(45);
  const [score, setScore] = useState(0);
  const [targetKana, setTargetKana] = useState<typeof KANA_DATA[0] | null>(null);
  const [candidates, setCandidates] = useState<Piece[]>([]);
  const [slots, setSlots] = useState<(Piece | null)[]>([null, null, null, null]);
  const [selectedCandidateId, setSelectedCandidateId] = useState<string | null>(null);
  const timerRef = useRef<number | null>(null);

  const shuffleArray = <T,>(array: T[]): T[] => {
    const newArr = [...array];
    for (let i = newArr.length - 1; i > 0; i--) {
      const j = Math.floor(Math.random() * (i + 1));
      [newArr[i], newArr[j]] = [newArr[j], newArr[i]];
    }
    return newArr;
  };

  const startNewRound = () => {
    const target = KANA_DATA[Math.floor(Math.random() * KANA_DATA.length)];
    const distractor = KANA_DATA[Math.floor(Math.random() * KANA_DATA.length)];
    setTargetKana(target);
    setSlots([null, null, null, null]);
    setSelectedCandidateId(null);

    // 4个正确的象限碎片
    const correctPieces: Piece[] = [0, 1, 2, 3].map(q => ({
      id: `correct-${q}-${Math.random()}`,
      char: target.char,
      quadrant: q,
      isDistractor: false
    }));

    // 1个干扰项 (随机取一个象限)
    const distractorPiece: Piece = {
      id: `wrong-${Math.random()}`,
      char: distractor.char === target.char ? 'あ' : distractor.char,
      quadrant: Math.floor(Math.random() * 4),
      isDistractor: true
    };

    setCandidates(shuffleArray([...correctPieces, distractorPiece]));
  };

  useEffect(() => {
    startNewRound();
    timerRef.current = window.setInterval(() => {
      setTimeLeft(prev => {
        if (prev <= 1) {
          if (timerRef.current) clearInterval(timerRef.current);
          return 0;
        }
        return prev - 1;
      });
    }, 1000);
    return () => { if (timerRef.current) clearInterval(timerRef.current); };
  }, []);

  useEffect(() => {
    if (timeLeft === 0) {
      onComplete(score);
    }
  }, [timeLeft]);

  const handleCandidateClick = (piece: Piece) => {
    // 如果已经在格子里的候选件，不能再次选择
    if (slots.some(s => s?.id === piece.id)) return;
    setSelectedCandidateId(piece.id === selectedCandidateId ? null : piece.id);
  };

  const handleSlotClick = (index: number) => {
    if (!selectedCandidateId) {
      // 如果点击已有碎片的格子，则撤回碎片
      if (slots[index]) {
        const newSlots = [...slots];
        newSlots[index] = null;
        setSlots(newSlots);
      }
      return;
    }

    const piece = candidates.find(c => c.id === selectedCandidateId);
    if (!piece) return;

    const newSlots = [...slots];
    // 如果该碎片已经在别的格子里，先移除
    const oldIndex = slots.findIndex(s => s?.id === piece.id);
    if (oldIndex !== -1) newSlots[oldIndex] = null;

    newSlots[index] = piece;
    setSlots(newSlots);
    setSelectedCandidateId(null);

    // 检查是否拼满
    if (newSlots.every(s => s !== null)) {
      const isCorrect = newSlots.every((s, i) => s?.char === targetKana?.char && s?.quadrant === i);
      if (isCorrect) {
        setScore(prev => prev + 20);
        setTimeout(startNewRound, 800);
      } else {
        // 错误反馈逻辑
        setScore(prev => Math.max(0, prev - 5));
        // 可选：高亮错误或清空
      }
    }
  };

  // 渲染碎片部分。逻辑：放大字符并定位，使其部分填满整个方块
  const renderFragment = (char: string, quadrant: number, isLarge: boolean = true) => {
    // quadrant 0:TL, 1:TR, 2:BL, 3:BR
    const scale = isLarge ? 2.1 : 1.8;
    const origins = ['top left', 'top right', 'bottom left', 'bottom right'];
    const offsets = [
      'translate(0, 0)', 
      'translate(-50%, 0)', 
      'translate(0, -50%)', 
      'translate(-50%, -50%)'
    ];

    return (
      <div className="relative w-full h-full overflow-hidden bg-white">
        <div 
          className="absolute font-black text-gray-800 leading-none select-none"
          style={{
            fontSize: isLarge ? '180px' : '120px',
            transform: `scale(${scale}) ${offsets[quadrant]}`,
            top: 0,
            left: 0,
          }}
        >
          {char}
        </div>
      </div>
    );
  };

  return (
    <div className="flex flex-col items-center py-2 space-y-6 animate-in fade-in duration-500">
      <button onClick={onBack} className="absolute -top-1 -left-2 p-2 text-gray-400 hover:text-[#FF6B6B] z-30">
        <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M15 19l-7-7 7-7" /></svg>
      </button>

      {/* 顶部状态栏 */}
      <div className="w-full px-4 flex justify-between items-center bg-white py-4 rounded-3xl border-2 border-orange-50 shadow-sm">
        <div className="text-center flex flex-col items-start">
          <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest">目标</span>
          <div className="text-3xl font-black text-blue-500">{targetKana?.char}</div>
        </div>
        <div className="text-center">
          <div className={`text-2xl font-black ${timeLeft < 10 ? 'text-red-500 animate-pulse' : 'text-[#FF6B6B]'}`}>
            {timeLeft}s
          </div>
          <span className="text-[8px] font-black text-gray-300 uppercase tracking-widest">TIME LEFT</span>
        </div>
        <div className="text-center flex flex-col items-end">
          <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest">SCORE</span>
          <div className="text-3xl font-black text-green-500">{score}</div>
        </div>
      </div>

      <p className="text-xs text-gray-400 font-bold px-4 text-center">
        点击下方碎片，填入中间十字格对应的位置
      </p>

      {/* 中间十字格 (2x2) */}
      <div className="grid grid-cols-2 gap-2 bg-gray-200 p-2 rounded-3xl shadow-inner relative w-64 h-64">
        {slots.map((slot, i) => (
          <button
            key={`slot-${i}`}
            onClick={() => handleSlotClick(i)}
            className={`w-full h-full rounded-xl overflow-hidden flex items-center justify-center transition-all bg-white/50 border-2 border-dashed ${
              !slot ? 'border-gray-300' : 'border-[#4ECDC4] shadow-md border-solid'
            } active:scale-95`}
          >
            {slot ? renderFragment(slot.char, slot.quadrant) : (
              <span className="text-gray-200 text-xs font-black">{['左上','右上','左下','右下'][i]}</span>
            )}
          </button>
        ))}
        {/* 辅助十字线 */}
        <div className="absolute top-1/2 left-0 right-0 h-0.5 bg-gray-100/30 pointer-events-none"></div>
        <div className="absolute left-1/2 top-0 bottom-0 w-0.5 bg-gray-100/30 pointer-events-none"></div>
      </div>

      {/* 候选碎片区 */}
      <div className="flex flex-row justify-between w-full px-2 gap-2">
        {/* 左侧候选 (3个) */}
        <div className="flex flex-col gap-3">
          {candidates.slice(0, 3).map((p) => (
            <button
              key={p.id}
              onClick={() => handleCandidateClick(p)}
              disabled={slots.some(s => s?.id === p.id)}
              className={`w-20 h-20 rounded-2xl overflow-hidden border-4 transition-all shadow-lg active:scale-90 ${
                slots.some(s => s?.id === p.id) ? 'opacity-20 grayscale scale-90' :
                selectedCandidateId === p.id ? 'border-[#4ECDC4] ring-4 ring-[#4ECDC4]/20 scale-105' : 'border-white hover:border-blue-100'
              }`}
            >
              {renderFragment(p.char, p.quadrant, false)}
            </button>
          ))}
        </div>

        {/* 右侧候选 (2个) */}
        <div className="flex flex-col gap-3 justify-center">
           {candidates.slice(3, 5).map((p) => (
            <button
              key={p.id}
              onClick={() => handleCandidateClick(p)}
              disabled={slots.some(s => s?.id === p.id)}
              className={`w-20 h-20 rounded-2xl overflow-hidden border-4 transition-all shadow-lg active:scale-90 ${
                slots.some(s => s?.id === p.id) ? 'opacity-20 grayscale scale-90' :
                selectedCandidateId === p.id ? 'border-[#4ECDC4] ring-4 ring-[#4ECDC4]/20 scale-105' : 'border-white hover:border-blue-100'
              }`}
            >
              {renderFragment(p.char, p.quadrant, false)}
            </button>
          ))}
        </div>
      </div>

      <div className="pt-2">
        <button 
          onClick={startNewRound}
          className="text-[10px] font-black text-gray-300 uppercase tracking-widest hover:text-blue-400 transition-colors"
        >
          跳过此题
        </button>
      </div>
    </div>
  );
};

export default PuzzleGame;

