import React, { useState, useEffect, useRef } from 'react';
import { KANA_DATA } from '../constants';

interface Piece {
  id: string;
  char: string;
  quadrant: number; // 0:左上, 1:右上, 2:左下, 3:右下
}

interface PuzzleGameProps {
  onComplete: (score: number) => void;
  onBack: () => void;
}

const PuzzleGame: React.FC<PuzzleGameProps> = ({ onComplete, onBack }) => {
  const [timeLeft, setTimeLeft] = useState(45);
  const [score, setScore] = useState(0);
  const [targetKana, setTargetKana] = useState<typeof KANA_DATA[0] | null>(null);
  const [candidates, setCandidates] = useState<Piece[]>([]);
  const [slots, setSlots] = useState<(Piece | null)[]>([null, null, null, null]);
  const timerRef = useRef<number | null>(null);

  const shuffleArray = <T,>(array: T[]): T[] => {
    const newArr = [...array];
    for (let i = newArr.length - 1; i > 0; i--) {
      const j = Math.floor(Math.random() * (i + 1));
      [newArr[i], newArr[j]] = [newArr[j], newArr[i]];
    }
    return newArr;
  };

  const startNewRound = () => {
    const target = KANA_DATA[Math.floor(Math.random() * KANA_DATA.length)];
    const distractorChar = KANA_DATA[Math.floor(Math.random() * KANA_DATA.length)].char;

    setTargetKana(target);
    setSlots([null, null, null, null]);

    // 4个正确的象限碎片
    const correctPieces: Piece[] = [0, 1, 2, 3].map(q => ({
      id: `correct-${q}-${Math.random()}`,
      char: target.char,
      quadrant: q
    }));

    // 1个干扰项
    const distractorPiece: Piece = {
      id: `wrong-${Math.random()}`,
      char: distractorChar === target.char ? 'ぬ' : distractorChar,
      quadrant: Math.floor(Math.random() * 4)
    };

    setCandidates(shuffleArray([...correctPieces, distractorPiece]));
  };

  useEffect(() => {
    startNewRound();
    timerRef.current = window.setInterval(() => {
      setTimeLeft(prev => {
        if (prev <= 1) {
          if (timerRef.current) clearInterval(timerRef.current);
          return 0;
        }
        return prev - 1;
      });
    }, 1000);
    return () => { if (timerRef.current) clearInterval(timerRef.current); };
  }, []);

  useEffect(() => {
    if (timeLeft === 0) {
      onComplete(score);
    }
  }, [timeLeft]);

  // 处理拖拽开始
  const onDragStart = (e: React.DragEvent, piece: Piece) => {
    e.dataTransfer.setData("pieceId", piece.id);
    e.dataTransfer.effectAllowed = "move";
  };

  // 处理拖拽进入放置区
  const onDragOver = (e: React.DragEvent) => {
    e.preventDefault();
    e.dataTransfer.dropEffect = "move";
  };

  // 处理放置
  const onDrop = (e: React.DragEvent, index: number) => {
    e.preventDefault();
    const pieceId = e.dataTransfer.getData("pieceId");
    const piece = candidates.find(p => p.id === pieceId);

    if (piece) {
      const newSlots = [...slots];
      // 如果该碎片已经在格子里了，先清空它原来的位置
      const existingIdx = newSlots.findIndex(s => s?.id === piece.id);
      if (existingIdx !== -1) newSlots[existingIdx] = null;

      newSlots[index] = piece;
      setSlots(newSlots);

      // 检查拼图是否完成
      if (newSlots.every(s => s !== null)) {
        const isAllCorrect = newSlots.every((s, i) => s?.char === targetKana?.char && s?.quadrant === i);
        if (isAllCorrect) {
          setScore(prev => prev + 20);
          setTimeout(startNewRound, 600);
        } else {
          setScore(prev => Math.max(0, prev - 5));
          // 拼错后可以点击格子撤回，或者等待自动清空
        }
      }
    }
  };

  // 点击格子撤回碎片
  const handleSlotClick = (index: number) => {
    if (slots[index]) {
      const newSlots = [...slots];
      newSlots[index] = null;
      setSlots(newSlots);
    }
  };

  // 渲染碎片内容
  const renderFragmentContent = (char: string, quadrant: number) => {
    // 偏移量：左上(0,0), 右上(-50%,0), 左下(0,-50%), 右下(-50%,-50%)
    const offsets = [
      'translate(0, 0)', 
      'translate(-50%, 0)', 
      'translate(0, -50%)', 
      'translate(-50%, -50%)'
    ];

    return (
      <div className="relative w-full h-full pointer-events-none overflow-hidden bg-white">
        <div 
          className="absolute font-black text-gray-800 leading-none select-none text-[160px]"
          style={{
            transform: `scale(2) ${offsets[quadrant]}`,
            top: '0px',
            left: '0px',
            transformOrigin: 'top left'
          }}
        >
          {char}
        </div>
      </div>
    );
