import React, { useState, useEffect, useRef } from 'react';
import { KANA_DATA } from '../constants';

interface Piece {
  id: string;
  char: string;
  quadrant: number; // 0:左上, 1:右上, 2:左下, 3:右下
}

interface PuzzleGameProps {
  onComplete: (score: number) => void;
  onBack: () => void;
}

const PuzzleGame: React.FC<PuzzleGameProps> = ({ onComplete, onBack }) => {
  const [timeLeft, setTimeLeft] = useState(45);
  const [score, setScore] = useState(0);
  const [targetKana, setTargetKana] = useState<typeof KANA_DATA[0] | null>(null);
  const [candidates, setCandidates] = useState<Piece[]>([]);
  const [slots, setSlots] = useState<(Piece | null)[]>([null, null, null, null]);
  const timerRef = useRef<number | null>(null);

  const shuffleArray = <T,>(array: T[]): T[] => {
    const newArr = [...array];
    for (let i = newArr.length - 1; i > 0; i--) {
      const j = Math.floor(Math.random() * (i + 1));
      [newArr[i], newArr[j]] = [newArr[j], newArr[i]];
    }
    return newArr;
  };

  const startNewRound = () => {
    // 随机选择目标假名和干扰假名
    const targetIdx = Math.floor(Math.random() * KANA_DATA.length);
    const target = KANA_DATA[targetIdx];

    let distractorIdx = Math.floor(Math.random() * KANA_DATA.length);
    while (distractorIdx === targetIdx) {
      distractorIdx = Math.floor(Math.random() * KANA_DATA.length);
    }
    const distractor = KANA_DATA[distractorIdx];

    setTargetKana(target);
    setSlots([null, null, null, null]);

    // 1. 生成目标假名的4个正确碎片
    const correctPieces: Piece[] = [0, 1, 2, 3].map(q => ({
      id: `correct-${q}-${Math.random()}`,
      char: target.char,
      quadrant: q
    }));

    // 2. 生成干扰假名的1个随机象限碎片
    const distractorPiece: Piece = {
      id: `wrong-${Math.random()}`,
      char: distractor.char,
      quadrant: Math.floor(Math.random() * 4)
    };

    // 3. 总共5个候选碎片
    setCandidates(shuffleArray([...correctPieces, distractorPiece]));
  };

  useEffect(() => {
    startNewRound();
    timerRef.current = window.setInterval(() => {
      setTimeLeft(prev => {
        if (prev <= 1) {
          if (timerRef.current) clearInterval(timerRef.current);
          return 0;
        }
        return prev - 1;
      });
    }, 1000);
    return () => { if (timerRef.current) clearInterval(timerRef.current); };
  }, []);

  useEffect(() => {
    if (timeLeft === 0) {
      onComplete(score);
    }
  }, [timeLeft]);

  const onDragStart = (e: React.DragEvent, piece: Piece) => {
    e.dataTransfer.setData("pieceId", piece.id);
    e.dataTransfer.effectAllowed = "move";
  };

  const onDragOver = (e: React.DragEvent) => {
    e.preventDefault();
    e.dataTransfer.dropEffect = "move";
  };

  const onDrop = (e: React.DragEvent, index: number) => {
    e.preventDefault();
    const pieceId = e.dataTransfer.getData("pieceId");
    const piece = candidates.find(p => p.id === pieceId);

    if (piece) {
      const newSlots = [...slots];
      const existingIdx = newSlots.findIndex(s => s?.id === piece.id);
      if (existingIdx !== -1) newSlots[existingIdx] = null;

      newSlots[index] = piece;
      setSlots(newSlots);

      // 检查拼图是否完成
      if (newSlots.every(s => s !== null)) {
        const isAllCorrect = newSlots.every((s, i) => 
          s?.char === targetKana?.char && s?.quadrant === i
        );

        if (isAllCorrect) {
          setScore(prev => prev + 20);
          // 延迟进入下一轮，给玩家看一眼完整的拼图
          setTimeout(startNewRound, 800);
        } else {
          setScore(prev => Math.max(0, prev - 5));
        }
      }
    }
  };

  const handleSlotClick = (index: number) => {
    if (slots[index]) {
      const newSlots = [...slots];
      newSlots[index] = null;
      setSlots(newSlots);
    }
  };

  /**
   * 核心渲染逻辑：精准切片
   * 将一个全尺寸的字符放在 200% 大小的容器中，并通过 absolute 定位来只显示特定象限
   */
  const renderFragmentContent = (char: string, quadrant: number) => {
    // 容器是 100% * 100% (比如 80px * 80px)
    // 字符层是 200% * 200% (比如 160px * 160px)
    // 根据象限平移：
    // 0 (左上): top: 0, left: 0
    // 1 (右上): top: 0, left: -100%
    // 2 (左下): top: -100%, left: 0
    // 3 (右下): top: -100%, left: -100%
    const positions = [
      { top: '0', left: '0' },
      { top: '0', left: '-100%' },
      { top: '-100%', left: '0' },
      { top: '-100%', left: '-100%' }
    ];

    return (
      <div className="relative w-full h-full pointer-events-none overflow-hidden bg-white select-none">
        <div 
          className="absolute w-[200%] h-[200%] flex items-center justify-center font-black text-gray-800"
          style={{
            top: positions[quadrant].top,
            left: positions[quadrant].left,
            fontSize: '120px', // 这里的字号取决于 200% 容器的大小，需要足够大
            lineHeight: '1',
          }}
        >
          {char}
        </div>
      </div>
    );
  };

  return (
    <div className="flex flex-col items-center py-2 space-y-6 animate-in fade-in duration-500 min-h-[600px]">
      <button onClick={onBack} className="absolute -top-1 -left-2 p-2 text-gray-400 hover:text-[#FF6B6B] z-30">
        <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M15 19l-7-7 7-7" /></svg>
      </button>

      {/* 状态栏 */}
      <div className="w-full px-4 flex justify-between items-center bg-white py-4 rounded-3xl border-2 border-[#FFE66D]/30 shadow-sm">
        <div className="text-center">
          <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest block mb-1">目标假名</span>
          <div className="text-3xl font-black text-[#FF6B6B] leading-none">{targetKana?.char}</div>
        </div>
        <div className="text-center">
          <div className={`text-2xl font-black ${timeLeft < 10 ? 'text-red-500 animate-pulse' : 'text-gray-700'}`}>
            {timeLeft}s
          </div>
          <span className="text-[8px] font-black text-gray-300 uppercase tracking-widest">倒计时</span>
        </div>
        <div className="text-center">
          <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest block mb-1">得分</span>
          <div className="text-3xl font-black text-[#4ECDC4] leading-none">{score}</div>
        </div>
      </div>

      <div className="text-center space-y-1">
        <p className="text-sm font-black text-gray-500">
          把碎片 <span className="text-[#FF6B6B]">拖入</span> 十字格
        </p>
        <p className="text-[10px] text-gray-300 font-bold uppercase tracking-wider italic">
          提示：有一个碎片是来捣乱的哦！
        </p>
      </div>

      {/* 拼图区域核心布局 */}
      <div className="flex w-full items-center justify-center px-2 gap-4 mt-2">

        {/* 左侧候选区 (3个) */}
        <div className="flex flex-col gap-3">
          {candidates.slice(0, 3).map((piece) => (
            <div
              key={piece.id}
              draggable={!slots.some(s => s?.id === piece.id)}
              onDragStart={(e) => onDragStart(e, piece)}
              className={`w-20 h-20 rounded-2xl overflow-hidden border-4 transition-all shadow-md cursor-grab active:cursor-grabbing ${
                slots.some(s => s?.id === piece.id) 
                  ? 'opacity-20 grayscale border-gray-100 scale-90' 
                  : 'border-white hover:border-[#4ECDC4] hover:shadow-lg'
              }`}
            >
              {renderFragmentContent(piece.char, piece.quadrant)}
            </div>
          ))}
        </div>

        {/* 中央十字格 (2x2) */}
        <div className="grid grid-cols-2 gap-1 bg-gray-100 p-2 rounded-[2.5rem] shadow-inner border-4 border-white w-64 h-64 relative">
          {slots.map((slot, i) => (
            <div
              key={`slot-${i}`}
              onDragOver={onDragOver}
              onDrop={(e) => onDrop(e, i)}
              onClick={() => handleSlotClick(i)}
              className={`w-full h-full rounded-2xl overflow-hidden flex items-center justify-center transition-all border-2 border-dashed relative group ${
                !slot 
                  ? 'bg-white/40 border-gray-300' 
                  : 'bg-white border-[#4ECDC4] shadow-md border-solid animate-in zoom-in-50 duration-200'
              }`}
            >
              {slot ? (
                renderFragmentContent(slot.char, slot.quadrant)
              ) : (
                <div className="text-[10px] text-gray-300 font-black opacity-30 select-none">
                  {['左上','右上','左下','右下'][i]}
                </div>
              )}
            </div>
          ))}
          {/* 十字准线装饰层 */}
          <div className="absolute top-1/2 left-4 right-4 h-[2px] bg-white/50 pointer-events-none rounded-full"></div>
          <div className="absolute left-1/2 top-4 bottom-4 w-[2px] bg-white/50 pointer-events-none rounded-full"></div>
        </div>

        {/* 右侧候选区 (2个) */}
        <div className="flex flex-col gap-3">
          {candidates.slice(3, 5).map((piece) => (
            <div
              key={piece.id}
              draggable={!slots.some(s => s?.id === piece.id)}
              onDragStart={(e) => onDragStart(e, piece)}
              className={`w-20 h-20 rounded-2xl overflow-hidden border-4 transition-all shadow-md cursor-grab active:cursor-grabbing ${
                slots.some(s => s?.id === piece.id) 
                  ? 'opacity-20 grayscale border-gray-100 scale-90' 
                  : 'border-white hover:border-[#4ECDC4] hover:shadow-lg'
              }`}
            >
              {renderFragmentContent(piece.char, piece.quadrant)}
            </div>
          ))}
        </div>
      </div>

      {/* 底部按钮 */}
      <div className="flex flex-col items-center gap-4 pt-4">
        <button 
          onClick={startNewRound}
          className="bg-white px-6 py-2 rounded-full text-xs font-black text-gray-400 hover:text-[#FF6B6B] border border-gray-100 shadow-sm transition-all active:scale-95"
        >
          太难了，换一题
        </button>
      </div>
    </div>
  );
};

export default PuzzleGame;

import React, { useState, useEffect, useRef } from 'react';
import { KANA_DATA } from '../constants';

interface Piece {
  id: string;
  char: string;
  quadrant: number; // 0:左上, 1:右上, 2:左下, 3:右下
}

interface PuzzleGameProps {
  onComplete: (score: number) => void;
  onBack: () => void;
}

const PuzzleGame: React.FC<PuzzleGameProps> = ({ onComplete, onBack }) => {
  const [round, setRound] = useState(1);
  const totalRounds = 5;
  const [timeLeft, setTimeLeft] = useState(45);
  const [score, setScore] = useState(0);
  const [targetKana, setTargetKana] = useState<typeof KANA_DATA[0] | null>(null);
  const [candidates, setCandidates] = useState<Piece[]>([]);
  const [slots, setSlots] = useState<(Piece | null)[]>([null, null, null, null]);
  const [roundComplete, setRoundComplete] = useState(false);
  const [lastRoundPoints, setLastRoundPoints] = useState<number | null>(null);

  const timerRef = useRef<number | null>(null);

  const shuffleArray = <T,>(array: T[]): T[] => {
    const newArr = [...array];
    for (let i = newArr.length - 1; i > 0; i--) {
      const j = Math.floor(Math.random() * (i + 1));
      [newArr[i], newArr[j]] = [newArr[j], newArr[i]];
    }
    return newArr;
  };

  const startNewRound = (isSkip = false) => {
    if (round >= totalRounds && !isSkip && roundComplete) {
        onComplete(score);
        return;
    }

    if (isSkip) {
        if (round >= totalRounds) {
            onComplete(score);
            return;
        }
        setRound(prev => prev + 1);
    }

    const targetIdx = Math.floor(Math.random() * KANA_DATA.length);
    const target = KANA_DATA[targetIdx];
    let distractorIdx = Math.floor(Math.random() * KANA_DATA.length);
    while (distractorIdx === targetIdx) {
      distractorIdx = Math.floor(Math.random() * KANA_DATA.length);
    }
    const distractor = KANA_DATA[distractorIdx];

    setTargetKana(target);
    setSlots([null, null, null, null]);
    setRoundComplete(false);
    setLastRoundPoints(null);
    setTimeLeft(45);

    const correctPieces: Piece[] = [0, 1, 2, 3].map(q => ({
      id: `correct-${q}-${Math.random()}`,
      char: target.char,
      quadrant: q
    }));

    const distractorPiece: Piece = {
      id: `wrong-${Math.random()}`,
      char: distractor.char,
      quadrant: Math.floor(Math.random() * 4)
    };

    setCandidates(shuffleArray([...correctPieces, distractorPiece]));

    if (timerRef.current) clearInterval(timerRef.current);
    timerRef.current = window.setInterval(() => {
      setTimeLeft(prev => {
        if (prev <= 1) {
          if (timerRef.current) clearInterval(timerRef.current);
          return 0;
        }
        return prev - 1;
      });
    }, 1000);
  };

  useEffect(() => {
    startNewRound();
    return () => { if (timerRef.current) clearInterval(timerRef.current); };
  }, []);

  const onDragStart = (e: React.DragEvent, piece: Piece) => {
    if (roundComplete) return;
    e.dataTransfer.setData("pieceId", piece.id);
  };

  const onDragOver = (e: React.DragEvent) => {
    e.preventDefault();
  };

  const onDrop = (e: React.DragEvent, index: number) => {
    if (roundComplete) return;
    e.preventDefault();
    const pieceId = e.dataTransfer.getData("pieceId");
    const piece = candidates.find(p => p.id === pieceId);

    if (piece) {
      const newSlots = [...slots];
      const existingIdx = newSlots.findIndex(s => s?.id === piece.id);
      if (existingIdx !== -1) newSlots[existingIdx] = null;

      newSlots[index] = piece;
      setSlots(newSlots);

      if (newSlots.every(s => s !== null)) {
        const isAllCorrect = newSlots.every((s, i) => 
          s?.char === targetKana?.char && s?.quadrant === i
        );

        if (isAllCorrect) {
          if (timerRef.current) clearInterval(timerRef.current);

          let roundPoints = 10; // 基础分
          if (timeLeft >= 20) roundPoints += 20; // 20秒以上完成+20
          else if (timeLeft >= 10) roundPoints += 10; // 10秒以上完成+10

          setScore(prev => prev + roundPoints);
          setLastRoundPoints(roundPoints);
          setRoundComplete(true);

          setTimeout(() => {
            if (round < totalRounds) {
                setRound(prev => prev + 1);
                startNewRound();
            } else {
                onComplete(score + roundPoints);
            }
          }, 1500);
        }
      }
    }
  };

  const handleSlotClick = (index: number) => {
    if (roundComplete) return;
    if (slots[index]) {
      const newSlots = [...slots];
      newSlots[index] = null;
      setSlots(newSlots);
    }
  };

  const renderFragmentContent = (char: string, quadrant: number) => {
    const positions = [
      { top: '0', left: '0' },
      { top: '0', left: '-100%' },
      { top: '-100%', left: '0' },
      { top: '-100%', left: '-100%' }
    ];

    return (
      <div className="relative w-full h-full pointer-events-none overflow-hidden bg-white select-none">
        <div 
          className="absolute w-[200%] h-[200%] flex items-center justify-center font-black text-gray-800"
          style={{
            top: positions[quadrant].top,
            left: positions[quadrant].left,
            fontSize: '120px',
            lineHeight: '1',
          }}
        >
          {char}
        </div>
      </div>
    );
  };

  return (
    <div className="flex flex-col items-center py-2 space-y-6 animate-in fade-in duration-500 min-h-[600px]">
      <button onClick={onBack} className="absolute -top-1 -left-2 p-2 text-gray-400 hover:text-[#FF6B6B] z-30">
        <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M15 19l-7-7 7-7" /></svg>
      </button>

      {/* 顶部面板 */}
      <div className="w-full px-4 flex justify-between items-center bg-white py-4 rounded-3xl border-2 border-[#FFE66D]/30 shadow-sm relative overflow-hidden">
        {roundComplete && (
            <div className="absolute inset-0 bg-[#4ECDC4] flex items-center justify-center animate-in slide-in-from-bottom duration-300 z-10">
                <span className="text-white font-black text-xl">正解！+{lastRoundPoints} 分</span>
            </div>
        )}
        <div className="text-center">
          <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest block mb-1">进度 {round}/{totalRounds}</span>
          <div className="text-3xl font-black text-[#FF6B6B] leading-none">{targetKana?.char}</div>
        </div>
        <div className="text-center">
          <div className={`text-2xl font-black ${timeLeft === 0 ? 'text-gray-300' : timeLeft < 10 ? 'text-red-500 animate-pulse' : 'text-gray-700'}`}>
            {timeLeft}s
          </div>
          <span className="text-[8px] font-black text-gray-300 uppercase tracking-widest">倒计时</span>
        </div>
        <div className="text-center">
          <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest block mb-1">总分</span>
          <div className="text-3xl font-black text-[#4ECDC4] leading-none">{score}</div>
        </div>
      </div>

      <div className="text-center space-y-1">
        <p className="text-sm font-black text-gray-500">
          拼出 <span className="text-[#FF6B6B] text-lg">「{targetKana?.char}」</span>
        </p>
        {timeLeft === 0 && (
            <p className="text-[10px] text-red-400 font-bold bg-red-50 px-2 py-0.5 rounded-full">时间到！继续完成可得基础10分</p>
        )}
      </div>

