import React, { useState, useEffect, useRef } from 'react';
import { KANA_DATA } from '../constants';

interface Piece {
  id: string;
  char: string;
  quadrant: number; // 0:左上, 1:右上, 2:左下, 3:右下
}

interface PuzzleGameProps {
  onComplete: (score: number) => void;
  onBack: () => void;
}

const PuzzleGame: React.FC<PuzzleGameProps> = ({ onComplete, onBack }) => {
  const [round, setRound] = useState(1);
  const totalRounds = 5;
  const [timeLeft, setTimeLeft] = useState(45);
  const [score, setScore] = useState(0);
  const [targetKana, setTargetKana] = useState<typeof KANA_DATA[0] | null>(null);
  const [candidates, setCandidates] = useState<Piece[]>([]);
  const [slots, setSlots] = useState<(Piece | null)[]>([null, null, null, null]);
  const [roundComplete, setRoundComplete] = useState(false);
  const [lastRoundPoints, setLastRoundPoints] = useState<number | null>(null);

  const timerRef = useRef<number | null>(null);

  const shuffleArray = <T,>(array: T[]): T[] => {
    const newArr = [...array];
    for (let i = newArr.length - 1; i > 0; i--) {
      const j = Math.floor(Math.random() * (i + 1));
      [newArr[i], newArr[j]] = [newArr[j], newArr[i]];
    }
    return newArr;
  };

  const startNewRound = (isSkip = false) => {
    // 如果是最后一题完成了，或者是点击跳过且是最后一题
    if (round >= totalRounds && (roundComplete || isSkip)) {
        onComplete(score);
        return;
    }

    // 如果是中途跳过
    if (isSkip) {
        setRound(prev => prev + 1);
    }

    const targetIdx = Math.floor(Math.random() * KANA_DATA.length);
    const target = KANA_DATA[targetIdx];
    let distractorIdx = Math.floor(Math.random() * KANA_DATA.length);
    while (distractorIdx === targetIdx) {
      distractorIdx = Math.floor(Math.random() * KANA_DATA.length);
    }
    const distractor = KANA_DATA[distractorIdx];

    setTargetKana(target);
    setSlots([null, null, null, null]);
    setRoundComplete(false);
    setLastRoundPoints(null);
    setTimeLeft(45);

    const correctPieces: Piece[] = [0, 1, 2, 3].map(q => ({
      id: `correct-${q}-${Math.random()}`,
      char: target.char,
      quadrant: q
    }));

    const distractorPiece: Piece = {
      id: `wrong-${Math.random()}`,
      char: distractor.char,
      quadrant: Math.floor(Math.random() * 4)
    };

    setCandidates(shuffleArray([...correctPieces, distractorPiece]));

    if (timerRef.current) clearInterval(timerRef.current);
    timerRef.current = window.setInterval(() => {
      setTimeLeft(prev => {
        if (prev <= 1) {
          if (timerRef.current) clearInterval(timerRef.current);
          return 0;
        }
        return prev - 1;
      });
    }, 1000);
  };

  useEffect(() => {
    startNewRound();
    return () => { if (timerRef.current) clearInterval(timerRef.current); };
  }, []);

  const onDragStart = (e: React.DragEvent, piece: Piece) => {
    if (roundComplete) return;
    e.dataTransfer.setData("pieceId", piece.id);
  };

  const onDragOver = (e: React.DragEvent) => {
    e.preventDefault();
  };

  const onDrop = (e: React.DragEvent, index: number) => {
    if (roundComplete) return;
    e.preventDefault();
    const pieceId = e.dataTransfer.getData("pieceId");
    const piece = candidates.find(p => p.id === pieceId);

    if (piece) {
      const newSlots = [...slots];
      const existingIdx = newSlots.findIndex(s => s?.id === piece.id);
      if (existingIdx !== -1) newSlots[existingIdx] = null;

      newSlots[index] = piece;
      setSlots(newSlots);

      if (newSlots.every(s => s !== null)) {
        const isAllCorrect = newSlots.every((s, i) => 
          s?.char === targetKana?.char && s?.quadrant === i
        );

        if (isAllCorrect) {
          if (timerRef.current) clearInterval(timerRef.current);

          let roundPoints = 10; // 基础分
          if (timeLeft >= 20) roundPoints += 20; // 20秒以上完成+20
          else if (timeLeft >= 10) roundPoints += 10; // 10秒以上完成+10

          setScore(prev => prev + roundPoints);
          setLastRoundPoints(roundPoints);
          setRoundComplete(true);

          setTimeout(() => {
            if (round < totalRounds) {
                setRound(prev => prev + 1);
                startNewRound();
            } else {
                onComplete(score + roundPoints);
            }
          }, 1500);
        }
      }
    }
  };

  const handleSlotClick = (index: number) => {
    if (roundComplete) return;
    if (slots[index]) {
      const newSlots = [...slots];
      newSlots[index] = null;
      setSlots(newSlots);
    }
  };

  const renderFragmentContent = (char: string, quadrant: number) => {
    const positions = [
      { top: '0', left: '0' },
      { top: '0', left: '-100%' },
      { top: '-100%', left: '0' },
      { top: '-100%', left: '-100%' }
    ];

    return (
      <div className="relative w-full h-full pointer-events-none overflow-hidden bg-white select-none">
        <div 
          className="absolute w-[200%] h-[200%] flex items-center justify-center font-black text-gray-800"
          style={{
            top: positions[quadrant].top,
            left: positions[quadrant].left,
            fontSize: '120px',
            lineHeight: '1',
          }}
        >
          {char}
        </div>
      </div>
    );
  };

  return (
    <div className="flex flex-col items-center py-2 space-y-6 animate-in fade-in duration-500 min-h-[600px]">
      <button onClick={onBack} className="absolute -top-1 -left-2 p-2 text-gray-400 hover:text-[#FF6B6B] z-30">
        <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M15 19l-7-7 7-7" /></svg>
      </button>

      {/* 顶部面板 */}
      <div className="w-full px-4 flex justify-between items-center bg-white py-4 rounded-3xl border-2 border-[#FFE66D]/30 shadow-sm relative overflow-hidden">
        {roundComplete && (
            <div className="absolute inset-0 bg-[#4ECDC4] flex items-center justify-center animate-in slide-in-from-bottom duration-300 z-10">
                <span className="text-white font-black text-xl">正解！+{lastRoundPoints} 分</span>
            </div>
        )}
        <div className="text-center">
          <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest block mb-1">进度 {round}/{totalRounds}</span>
          <div className="text-3xl font-black text-[#FF6B6B] leading-none">{targetKana?.char}</div>
        </div>
        <div className="text-center">
          <div className={`text-2xl font-black ${timeLeft === 0 ? 'text-gray-300' : timeLeft < 10 ? 'text-red-500 animate-pulse' : 'text-gray-700'}`}>
            {timeLeft}s
          </div>
          <span className="text-[8px] font-black text-gray-300 uppercase tracking-widest">倒计时</span>
        </div>
        <div className="text-center">
          <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest block mb-1">总分</span>
          <div className="text-3xl font-black text-[#4ECDC4] leading-none">{score}</div>
        </div>
      </div>

      <div className="text-center space-y-1">
        <p className="text-sm font-black text-gray-500">
          拼出 <span className="text-[#FF6B6B] text-lg">「{targetKana?.char}」</span>
        </p>
        {timeLeft === 0 && (
            <p className="text-[10px] text-red-500 font-black bg-red-50 px-3 py-1 rounded-full animate-pulse border border-red-100">时间到</p>
        )}
      </div>

      {/* 拼图区域 */}
      <div className="flex w-full items-center justify-center px-2 gap-4 mt-2">
        <div className="flex flex-col gap-3">
          {candidates.slice(0, 3).map((piece) => (
            <div
              key={piece.id}
              draggable={!slots.some(s => s?.id === piece.id) && !roundComplete}
              onDragStart={(e) => onDragStart(e, piece)}
