                </div>
              )}
            </div>
          ))}
          <div className="absolute top-1/2 left-4 right-4 h-[2px] bg-white/50 pointer-events-none rounded-full"></div>
          <div className="absolute left-1/2 top-4 bottom-4 w-[2px] bg-white/50 pointer-events-none rounded-full"></div>
        </div>

        <div className="flex flex-col gap-3">
          {candidates.slice(3, 5).map((piece) => (
