        </div>
      </div>

      <div className="flex flex-col items-center gap-4 pt-4">
        <button 
          onClick={() => startNewRound(true)}
          className="bg-white px-8 py-3 rounded-full text-sm font-black text-gray-400 hover:text-[#FF6B6B] border-2 border-gray-100 shadow-sm transition-all active:scale-95 flex items-center gap-2"
