import React, { useState, useEffect } from 'react';
import { UserRole } from './types';
import Layout from './components/Layout';
import StudentHome from './components/StudentHome';
import TeacherDashboard from './components/TeacherDashboard';
import KanaGame from './components/KanaGame';
import PuzzleGame from './components/PuzzleGame';

interface RegisteredStudent {
  name: string;
  className: string;
  studentId: string;
}

const Logo: React.FC<{ className?: string }> = ({ className }) => (
  <svg viewBox="0 0 512 512" className={className} xmlns="http://www.w3.org/2000/svg">
    <circle cx="320" cy="220" r="140" fill="#E62117" />
    <path d="M256 120 L480 440 H32 L256 120Z" fill="white" />
    <path d="M256 145 L450 420 H62 L256 145Z" fill="#E62117" />
    <path d="M256 145 L320 235 L285 215 L256 235 L227 215 L192 235 Z" fill="white" />
  </svg>
);

const App: React.FC = () => {
  const [role, setRole] = useState<UserRole | null>(null);
  const [activeModule, setActiveModule] = useState<string | null>(null);
  const [studentInfo, setStudentInfo] = useState<RegisteredStudent | null>(null);
  const [regForm, setRegForm] = useState({ name: '', className: '', studentId: '' });

  useEffect(() => {
    const saved = localStorage.getItem('nihongo_student_reg');
    if (saved) {
      setStudentInfo(JSON.parse(saved));
    }
  }, []);

  const handleLogout = () => {
    setRole(null);
    setActiveModule(null);
  };

  const handleRegister = (e: React.FormEvent) => {
    e.preventDefault();
    if (regForm.name && regForm.className && regForm.studentId) {
      const info = { ...regForm };
      setStudentInfo(info);
      localStorage.setItem('nihongo_student_reg', JSON.stringify(info));
    }
  };

  // 1. 初始选择角色界面
  if (!role) {
    return (
      <div className="min-h-screen bg-[#FFFAF0] flex items-center justify-center p-8">
        <div className="bg-white w-full max-w-sm rounded-[3rem] shadow-[0_30px_60px_rgba(255,107,107,0.15)] p-10 space-y-10 border-b-8 border-gray-100 relative overflow-hidden text-center">
          <div className="absolute top-[-40px] left-[-40px] w-40 h-40 bg-[#FFE66D]/30 rounded-full blur-3xl"></div>
          <div className="relative">
            <div className="w-32 h-32 mx-auto mb-6 transform rotate-6 hover:rotate-0 transition-transform duration-500">
              <Logo className="w-full h-full drop-shadow-2xl" />
            </div>
            <h1 className="text-4xl font-black text-gray-900 tracking-tight leading-tight">日语起跑线</h1>
            <p className="text-gray-400 mt-3 font-bold text-sm tracking-widest uppercase">Japanese Starting Line</p>
          </div>
          <div className="space-y-4">
            <button
              onClick={() => setRole(UserRole.STUDENT)}
              className="w-full bg-[#FF6B6B] text-white py-5 rounded-3xl font-black text-xl hover:bg-[#FF5252] active:scale-95 transition-all shadow-xl"
            >
              我是学生
            </button>
            <button
              onClick={() => setRole(UserRole.TEACHER)}
              className="w-full bg-white border-4 border-gray-100 text-gray-500 py-5 rounded-3xl font-black text-xl hover:border-[#4ECDC4] hover:text-[#4ECDC4] active:scale-95 transition-all shadow-sm"
            >
              教师入口
            </button>
          </div>
          <p className="text-[10px] text-gray-300 uppercase tracking-[0.3em] font-black">高校教学专用版 V1.0</p>
        </div>
      </div>
    );
  }

  // 2. 如果是学生且未注册，显示注册表单
  if (role === UserRole.STUDENT && !studentInfo) {
    return (
      <div className="min-h-screen bg-[#FFFAF0] flex items-center justify-center p-8">
        <form onSubmit={handleRegister} className="bg-white w-full max-w-sm rounded-[3rem] shadow-2xl p-10 space-y-6 border-b-8 border-gray-100 animate-in zoom-in-95 duration-500">
          <div className="text-center">
            <h2 className="text-2xl font-black text-gray-800">新成员报到</h2>
            <p className="text-sm text-gray-400 font-bold mt-1">请完善你的学习档案</p>
          </div>
          <div className="space-y-4">
            <div>
              <label className="text-xs font-black text-gray-400 uppercase ml-2 mb-1 block">真实姓名</label>
              <input 
                required
                type="text" 
                value={regForm.name}
                onChange={(e) => setRegForm({...regForm, name: e.target.value})}
                placeholder="请输入姓名"
                className="w-full px-6 py-4 rounded-2xl bg-gray-50 border-2 border-transparent focus:border-[#FF6B6B] outline-none font-bold transition-all"
              />
            </div>
            <div>
              <label className="text-xs font-black text-gray-400 uppercase ml-2 mb-1 block">班级名称</label>
              <input 
                required
                type="text" 
                value={regForm.className}
                onChange={(e) => setRegForm({...regForm, className: e.target.value})}
                placeholder="例如：日语入门 A班"
                className="w-full px-6 py-4 rounded-2xl bg-gray-50 border-2 border-transparent focus:border-[#FF6B6B] outline-none font-bold transition-all"
              />
            </div>
            <div>
              <label className="text-xs font-black text-gray-400 uppercase ml-2 mb-1 block">学号</label>
              <input 
                required
                type="text" 
                value={regForm.studentId}
                onChange={(e) => setRegForm({...regForm, studentId: e.target.value})}
                placeholder="请输入学号"
                className="w-full px-6 py-4 rounded-2xl bg-gray-50 border-2 border-transparent focus:border-[#FF6B6B] outline-none font-bold transition-all"
              />
            </div>
          </div>
          <button
            type="submit"
            className="w-full bg-[#4ECDC4] text-white py-5 rounded-3xl font-black text-lg shadow-lg active:scale-95 transition-all"
          >
            开启学习之旅
          </button>
        </form>
      </div>
    );
  }

  const renderContent = () => {
    if (role === UserRole.TEACHER) {
      return <TeacherDashboard />;
    }

    switch (activeModule) {
      case 'm1':
        return (
          <KanaGame 
            onBack={() => setActiveModule(null)}
            onComplete={(score) => {
              alert(`挑战完成！你的得分: ${score}`);
              setActiveModule(null);
            }} 
          />
        );
      case 'm2':
        return (
          <PuzzleGame 
            onBack={() => setActiveModule(null)}
            onComplete={(score) => {
              alert(`拼图挑战结束！总得分: ${score}`);
              setActiveModule(null);
            }} 
          />
        );
      default:
        return <StudentHome onSelectModule={(id) => setActiveModule(id)} studentData={studentInfo!} />;
    }
  };

  return (
    <Layout 
      role={role} 
      onLogout={handleLogout} 
      title={role === UserRole.STUDENT ? '学生端' : '教师控制台'}
    >
      {renderContent()}
    </Layout>
  );
};

export default App;

