import React, { useEffect, useState } from 'react';
import { MODULES, MOCK_STUDENTS } from '../constants';
import { generateStudyEncouragement } from '../services/geminiService';

interface StudentHomeProps {
  onSelectModule: (moduleId: string) => void;
  studentData: { name: string; className: string; studentId: string; totalPoints: number };
}

const StudentHome: React.FC<StudentHomeProps> = ({ onSelectModule, studentData }) => {
  const [zen, setZen] = useState<string>('正在获取每日寄语...');
  const [showRanking, setShowRanking] = useState(false);

  // Use first student from mocks as a base for additional stats if needed
  const displayStats = MOCK_STUDENTS[0]; 

  useEffect(() => {
    generateStudyEncouragement(studentData).then(setZen).catch(() => setZen('加油！每天进步一点点。'));
  }, [studentData.name]);

  // Combine current student with mock students for leaderboard
  const leaderboard = [
    { name: studentData.name, totalPoints: studentData.totalPoints, isMe: true },
    ...MOCK_STUDENTS.filter(s => s.name !== studentData.name).map(s => ({ name: s.name, totalPoints: s.totalPoints, isMe: false }))
  ].sort((a, b) => b.totalPoints - a.totalPoints);

  const myRank = leaderboard.findIndex(s => s.isMe) + 1;

  if (showRanking) {
    return (
      <div className="space-y-6 animate-in fade-in slide-in-from-right duration-300">
        <div className="flex items-center justify-between px-1">
          <button onClick={() => setShowRanking(false)} className="p-2 text-gray-400 hover:text-[#FF6B6B] transition-colors">
            <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M15 19l-7-7 7-7" /></svg>
