const App: React.FC = () => {
  const [role, setRole] = useState<UserRole | null>(null);
  const [activeModule, setActiveModule] = useState<string | null>(null);
  const [studentInfo, setStudentInfo] = useState<RegisteredStudent | null>(null);
  const [regForm, setRegForm] = useState({ name: '', className: '', studentId: '' });
  const [totalPoints, setTotalPoints] = useState<number>(0);

  useEffect(() => {
    // 1. Load Student Info
    const savedReg = localStorage.getItem('nihongo_student_reg');
    if (savedReg) {
      setStudentInfo(JSON.parse(savedReg));
    }

    // 2. Load Points
    const savedPoints = localStorage.getItem('nihongo_total_points');
    const currentPoints = savedPoints ? parseInt(savedPoints, 10) : 0;

    // 3. Check for Weekly Reset
    const checkAndReset = (points: number) => {
      const configStr = localStorage.getItem('nihongo_reset_config');
      const config: ResetConfig = configStr ? JSON.parse(configStr) : { day: 1, hour: 12 }; // Default Monday 12:00
      const lastResetStr = localStorage.getItem('nihongo_last_reset_time');

      const now = new Date();
      const lastScheduled = new Date(now);

      // Calculate most recent scheduled reset
      let diff = now.getDay() - config.day;
      if (diff < 0) diff += 7;

      lastScheduled.setDate(now.getDate() - diff);
      lastScheduled.setHours(config.hour, 0, 0, 0);

      // If scheduled time for today hasn't passed yet, go back a week
      if (lastScheduled > now) {
        lastScheduled.setDate(lastScheduled.getDate() - 7);
      }

      if (!lastResetStr || new Date(parseInt(lastResetStr)) < lastScheduled) {
        setTotalPoints(0);
        localStorage.setItem('nihongo_total_points', '0');
        localStorage.setItem('nihongo_last_reset_time', lastScheduled.getTime().toString());
        return 0;
      }
      return points;
    };

    const validatedPoints = checkAndReset(currentPoints);
    setTotalPoints(validatedPoints);
  }, []);

  const handleLogout = () => {
    setRole(null);
    setActiveModule(null);
  };

  const handleRegister = (e: React.FormEvent) => {
    e.preventDefault();
    if (regForm.name && regForm.className && regForm.studentId) {
      const info = { ...regForm };
      setStudentInfo(info);
      localStorage.setItem('nihongo_student_reg', JSON.stringify(info));
    }
  };

  const updatePoints = (earned: number) => {
    const newTotal = totalPoints + earned;
    setTotalPoints(newTotal);
    localStorage.setItem('nihongo_total_points', newTotal.toString());
  };

  // 1. 初始选择角色界面
  if (!role) {
    return (
      <div className="min-h-screen bg-[#FFFAF0] flex items-center justify-center p-8">
        <div className="bg-white w-full max-w-sm rounded-[3rem] shadow-[0_30px_60px_rgba(255,107,107,0.15)] p-10 space-y-10 border-b-8 border-gray-100 relative overflow-hidden text-center">
