                <input required type="text" value={regForm.name} onChange={(e) => setRegForm({...regForm, name: e.target.value})} placeholder="姓名" className="w-full px-5 py-3 rounded-2xl bg-gray-50 border-2 border-transparent focus:border-[#FF6B6B] outline-none font-bold text-sm transition-all" />
              </div>
              <div>
                <label className="text-[10px] font-black text-gray-400 uppercase ml-2 mb-1 block">班级名称</label>
                <input required type="text" value={regForm.className} onChange={(e) => setRegForm({...regForm, className: e.target.value})} placeholder="例如：日语A班" className="w-full px-5 py-3 rounded-2xl bg-gray-50 border-2 border-transparent focus:border-[#FF6B6B] outline-none font-bold text-sm transition-all" />
              </div>
              <div>
                <label className="text-[10px] font-black text-gray-400 uppercase ml-2 mb-1 block">学号</label>
                <input required type="text" value={regForm.studentId} onChange={(e) => setRegForm({...regForm, studentId: e.target.value})} placeholder="学号" className="w-full px-5 py-3 rounded-2xl bg-gray-50 border-2 border-transparent focus:border-[#FF6B6B] outline-none font-bold text-sm transition-all" />
              </div>
            </div>
            <button type="submit" className="w-full bg-[#4ECDC4] text-white py-4 rounded-2xl font-black shadow-lg active:scale-95 transition-all">
              开启学习之旅
            </button>
          </form>
        </div>
      </DeviceFrame>
    );
  }

  const renderContent = () => {
    if (role === UserRole.TEACHER) {
      return <TeacherDashboard />;
    }

    switch (activeModule) {
      case 'm1':
        return (
          <KanaGame 
            onBack={() => setActiveModule(null)}
            onComplete={(score) => {
              updatePoints(score);
              setActiveModule(null);
            }} 
          />
        );
      case 'm2':
        return (
          <PuzzleGame 
            onBack={() => setActiveModule(null)}
            onComplete={(score) => {
              updatePoints(score);
              setActiveModule(null);
            }} 
          />
        );
      default:
        return (
          <StudentHome 
            onSelectModule={(id) => setActiveModule(id)} 
            studentData={{...studentInfo!, totalPoints}} 
          />
        );
    }
  };

  return (
    <DeviceFrame>
      <Layout 
        role={role} 
        onLogout={handleLogout} 
        title={role === UserRole.STUDENT ? '学生端' : '教师控制台'}
      >
        {renderContent()}
      </Layout>
    </DeviceFrame>
  );
};

export default App;

