}

const Logo: React.FC<{ className?: string }> = ({ className }) => (
  <svg viewBox="0 0 100 100" className={className} xmlns="http://www.w3.org/2000/svg">
    <circle cx="66" cy="38" r="26" fill="#E62117" />
    <path d="M10 82 L75 82 L42.5 28 Z" fill="#E62117" />
