            <input required type="text" value={regForm.className} onChange={(e) => setRegForm({...regForm, className: e.target.value})} placeholder="班级（如：日语A班）" className="w-full px-5 py-4 rounded-2xl bg-gray-50 border-2 border-transparent focus:border-[#FF6B6B] outline-none font-bold text-sm transition-all" />
            <input required type="text" value={regForm.studentId} onChange={(e) => setRegForm({...regForm, studentId: e.target.value})} placeholder="学号" className="w-full px-5 py-4 rounded-2xl bg-gray-50 border-2 border-transparent focus:border-[#FF6B6B] outline-none font-bold text-sm transition-all" />
            <button type="submit" className="w-full bg-[#4ECDC4] text-white py-4 rounded-2xl font-black shadow-lg active:scale-95 transition-all mt-4">
              开始学习
            </button>
          </form>
        </div>
      </div>
    );
  }

  const renderContent = () => {
    if (role === UserRole.TEACHER) return <TeacherDashboard />;
    if (activeModule === 'm1') return <KanaGame onBack={() => setActiveModule(null)} onComplete={(s) => { updatePoints(s); setActiveModule(null); }} />;
    if (activeModule === 'm2') return <PuzzleGame onBack={() => setActiveModule(null)} onComplete={(s) => { updatePoints(s); setActiveModule(null); }} />;
    return <StudentHome onSelectModule={(id) => setActiveModule(id)} studentData={{...studentInfo!, totalPoints}} />;
  };

  return (
    <Layout 
      role={role} 
      onLogout={handleLogout} 
      title={role === UserRole.STUDENT ? '学生学习中心' : '教师控制台'}
    >
      {renderContent()}
    </Layout>
  );
};

export default App;

